import{_ as s,o as a,c as i,ai as t}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"OAuth","description":"","frontmatter":{"summary":"OAuth in OpenSoul: token exchange, storage, and multi-account patterns","read_when":["You want to understand OpenSoul OAuth end-to-end","You hit token invalidation / logout issues","You want setup-token or OAuth auth flows","You want multiple accounts or profile routing"],"title":"OAuth"},"headers":[],"relativePath":"concepts/oauth.md","filePath":"concepts/oauth.md","lastUpdated":1771906665000}'),o={name:"concepts/oauth.md"};function n(l,e,r,p,h,d){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="oauth" tabindex="-1"><a class="header-anchor" href="#oauth">#</a> OAuth</h1><p>OpenSoul supports “subscription auth” via OAuth for providers that offer it (notably <strong>OpenAI Codex (ChatGPT OAuth)</strong>). For Anthropic subscriptions, use the <strong>setup-token</strong> flow. This page explains:</p><ul><li>how the OAuth <strong>token exchange</strong> works (PKCE)</li><li>where tokens are <strong>stored</strong> (and why)</li><li>how to handle <strong>multiple accounts</strong> (profiles + per-session overrides)</li></ul><p>OpenSoul also supports <strong>provider plugins</strong> that ship their own OAuth or API‑key flows. Run them via:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="the-token-sink-why-it-exists" tabindex="-1"><a class="header-anchor" href="#the-token-sink-why-it-exists">#</a> The token sink (why it exists)</h2><p>OAuth providers commonly mint a <strong>new refresh token</strong> during login/refresh flows. Some providers (or OAuth clients) can invalidate older refresh tokens when a new one is issued for the same user/app.</p><p>Practical symptom:</p><ul><li>you log in via OpenSoul <em>and</em> via Claude Code / Codex CLI → one of them randomly gets “logged out” later</li></ul><p>To reduce that, OpenSoul treats <code>auth-profiles.json</code> as a <strong>token sink</strong>:</p><ul><li>the runtime reads credentials from <strong>one place</strong></li><li>we can keep multiple profiles and route them deterministically</li></ul><h2 id="storage-where-tokens-live" tabindex="-1"><a class="header-anchor" href="#storage-where-tokens-live">#</a> Storage (where tokens live)</h2><p>Secrets are stored <strong>per-agent</strong>:</p><ul><li>Auth profiles (OAuth + API keys): <code>~/.opensoul/agents/&lt;agentId&gt;/agent/auth-profiles.json</code></li><li>Runtime cache (managed automatically; don’t edit): <code>~/.opensoul/agents/&lt;agentId&gt;/agent/auth.json</code></li></ul><p>Legacy import-only file (still supported, but not the main store):</p><ul><li><code>~/.opensoul/credentials/oauth.json</code> (imported into <code>auth-profiles.json</code> on first use)</li></ul><p>All of the above also respect <code>$OPENSOUL_STATE_DIR</code> (state dir override). Full reference: <a href="/docs/gateway/configuration#auth-storage-oauth--api-keys">/gateway/configuration</a></p><h2 id="anthropic-setup-token-subscription-auth" tabindex="-1"><a class="header-anchor" href="#anthropic-setup-token-subscription-auth">#</a> Anthropic setup-token (subscription auth)</h2><p>Run <code>claude setup-token</code> on any machine, then paste it into OpenSoul:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If you generated the token elsewhere, paste it manually:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> paste-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Verify:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="oauth-exchange-how-login-works" tabindex="-1"><a class="header-anchor" href="#oauth-exchange-how-login-works">#</a> OAuth exchange (how login works)</h2><p>OpenSoul’s interactive login flows are implemented in <code>@mariozechner/pi-ai</code> and wired into the wizards/commands.</p><h3 id="anthropic-claude-pro-max-setup-token" tabindex="-1"><a class="header-anchor" href="#anthropic-claude-pro-max-setup-token">#</a> Anthropic (Claude Pro/Max) setup-token</h3><p>Flow shape:</p><ol><li>run <code>claude setup-token</code></li><li>paste the token into OpenSoul</li><li>store as a token auth profile (no refresh)</li></ol><p>The wizard path is <code>opensoul onboard</code> → auth choice <code>setup-token</code> (Anthropic).</p><h3 id="openai-codex-chatgpt-oauth" tabindex="-1"><a class="header-anchor" href="#openai-codex-chatgpt-oauth">#</a> OpenAI Codex (ChatGPT OAuth)</h3><p>Flow shape (PKCE):</p><ol><li>generate PKCE verifier/challenge + random <code>state</code></li><li>open <code>https://auth.openai.com/oauth/authorize?...</code></li><li>try to capture callback on <code>http://127.0.0.1:1455/auth/callback</code></li><li>if callback can’t bind (or you’re remote/headless), paste the redirect URL/code</li><li>exchange at <code>https://auth.openai.com/oauth/token</code></li><li>extract <code>accountId</code> from the access token and store <code>{ access, refresh, expires, accountId }</code></li></ol><p>Wizard path is <code>opensoul onboard</code> → auth choice <code>openai-codex</code>.</p><h2 id="refresh-expiry" tabindex="-1"><a class="header-anchor" href="#refresh-expiry">#</a> Refresh + expiry</h2><p>Profiles store an <code>expires</code> timestamp.</p><p>At runtime:</p><ul><li>if <code>expires</code> is in the future → use the stored access token</li><li>if expired → refresh (under a file lock) and overwrite the stored credentials</li></ul><p>The refresh flow is automatic; you generally don&#39;t need to manage tokens manually.</p><h2 id="multiple-accounts-profiles-routing" tabindex="-1"><a class="header-anchor" href="#multiple-accounts-profiles-routing">#</a> Multiple accounts (profiles) + routing</h2><p>Two patterns:</p><h3 id="_1-preferred-separate-agents" tabindex="-1"><a class="header-anchor" href="#_1-preferred-separate-agents">#</a> 1) Preferred: separate agents</h3><p>If you want “personal” and “work” to never interact, use isolated agents (separate sessions + credentials + workspace):</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> work</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> personal</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Then configure auth per-agent (wizard) and route chats to the right agent.</p><h3 id="_2-advanced-multiple-profiles-in-one-agent" tabindex="-1"><a class="header-anchor" href="#_2-advanced-multiple-profiles-in-one-agent">#</a> 2) Advanced: multiple profiles in one agent</h3><p><code>auth-profiles.json</code> supports multiple profile IDs for the same provider.</p><p>Pick which profile is used:</p><ul><li>globally via config ordering (<code>auth.order</code>)</li><li>per-session via <code>/model ...@&lt;profileId&gt;</code></li></ul><p>Example (session override):</p><ul><li><code>/model Opus@anthropic:work</code></li></ul><p>How to see what profile IDs exist:</p><ul><li><code>opensoul channels list --json</code> (shows <code>auth[]</code>)</li></ul><p>Related docs:</p><ul><li><a href="/docs/concepts/model-failover">/concepts/model-failover</a> (rotation + cooldown rules)</li><li><a href="/docs/tools/slash-commands">/tools/slash-commands</a> (command surface)</li></ul>`,55)])])}const k=s(o,[["render",n]]);export{u as __pageData,k as default};
